parameters.functionCode:
// Process Instagram data
const posts = items[0].json.posts || [];
const analysis = items[0].json.analysis || {};

// Extract insights
const insights = {
  totalPosts: posts.length,
  avgEngagement: posts.reduce((sum, p) => sum + p.likes + p.comments, 0) / posts.length,
  topPerformer: posts.reduce((max, p) => (p.likes + p.comments) > (max.likes + max.comments) ? p : max, posts[0]),
  recommendations: analysis.performance_insights?.content_recommendations || []
};

return [{json: insights}];

parameters.text:
New Instagram analysis complete!

Total Posts: {{$json.totalPosts}}
Avg Engagement: {{$json.avgEngagement}}
Top Post: {{$json.topPerformer.shortcode}}

Recommendations:
{{$json.recommendations.join('\n')}}
